        if not valid: continue
        # get first few y values per curve to see shape
        yvals = {}
        for i, p in valid:
            yvals[p] = []
        for row in rows[:10]:
            for i, p in valid:
                if i+1 < len(row) and row[i+1].strip() not in ('', 'nan'):
                    yvals[p].append(float(row[i+1]))
        name = os.path.relpath(dirpath, data_root)
        for p, ys in list(yvals.items())[:2]:
            if ys:
                print(f'{name} x1={p}: y[0:5]={[round(v,3) for v in ys[:5]]}')
